class Solution:
    def numberOfPairs(self, nums1, nums2, k):
        from collections import Counter
        freq = Counter(nums1)
        max_val = max(nums1)
        count = 0
        for b in set(nums2):
            mult_b = nums2.count(b)
            prod = b * k
            if prod > max_val:
                continue
            multiple = prod
            while multiple <= max_val:
                if multiple in freq:
                    count += freq[multiple] * mult_b
                multiple += prod
        return count

