var numberOfPairs = function(nums1, nums2, k) {
    const freq = new Map();
    let maxVal = 0;
    for (const a of nums1) {
        freq.set(a, (freq.get(a) || 0) + 1);
        if (a > maxVal) maxVal = a;
    }
    const cnt2 = new Map();
    for (const b of nums2) {
        cnt2.set(b, (cnt2.get(b) || 0) + 1);
    }
    let count = 0;
    for (const [b, multB] of cnt2) {
        const prod = b * k;
        if (prod > maxVal) continue;
        for (let multiple = prod; multiple <= maxVal; multiple += prod) {
            if (freq.has(multiple)) {
                count += freq.get(multiple) * multB;
            }
        }
    }
    return count;
};
